import javax.servlet.*;
import javax.servlet.http.*;  // HttpServletRequest, HttpServletResponse classes are used here for request handling operations only - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)  
import java.io.*;          // Input/Output streams and their respective IOC (Input / Output Converters), PrintWriter classes are used here for writing data to the HTTP response - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.util.*;        // For using some built-in utility functions such hashlib, get_hex(hash), etc – used here for hashing passwords - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.security.*;   // For using SHA-256 algorithm to hash the input data (password). This is only required when storing actual hashed passwords - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.util.Base64.*; // For using Base 64 algorithm for encoding the hash into base-64 format, required when sending response data back to client - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.nio.charset.*; // For handling different encodings (UTF8/ISO 8859-1), required when sending response data back to client - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.nio.ByteBuffer; // For handling byte buffers, used for encoding Base64 strings (required by ByteBuffer class), required when sending response data back to client - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.security.MessageDigest;  // For using SHA-256 algorithm for hashing (required by MessageDigest class), used here when storing the actual passwords - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)
import java.security.NoSuchAlgorithmException; // For handling different encryption algorithms, required to hash data (required by MessageDigest class), used here when storing the actual passwords - not necessary if you use standard libraries alone then we can ignore them as they're unnecessary dependencies in a simple program like this one:)